import triton
import triton.language as tl

@triton.jit
def sum_kernel(X_ptr, Y_ptr, N, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < N
    x = tl.load(X_ptr + offsets, mask=mask, other=0.0)
    sum_val = tl.sum(x, axis=0)
    tl.atomic_add(Y_ptr, sum_val)

@triton.jit
def std_kernel(X_ptr, Mean, Out_ptr, N, correction, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < N
    x = tl.load(X_ptr + offsets, mask=mask, other=0.0)
    diff = x - tl.load(Mean)
    sq = diff * diff
    sum_sq = tl.sum(sq, axis=0)
    tl.atomic_add(Out_ptr, sum_sq)

def _triton_sum(x, dim=None, keepdim=False, dtype=None):
    if dtype is not None:
        x = x.to(dtype)
    if dim is None:
        x_flat = x.flatten()
    else:
        s = list(x.shape)
        d = dim if isinstance(dim, tuple) else (dim,)
        for dim_ in sorted(d, reverse=True):
            s.pop(dim_)
        if len(s) == 0:
            x_flat = x.flatten()
        else:
            x_flat = x.permute(*[i for i in range(x.ndim) if i not in d], *d).reshape(s + [-1]).flatten()

    N = x_flat.numel()
    out = torch.zeros(1, device=x.device, dtype=x_flat.dtype)
    BLOCK_SIZE = 1024
    grid = (triton.cdiv(N, BLOCK_SIZE),)
    sum_kernel[grid](x_flat, out, N, BLOCK_SIZE=BLOCK_SIZE)
    if keepdim:
        if dim is None:
            return out.reshape([1]*x.ndim)
        else:
            shape = list(x.shape)
            for d_ in sorted((dim,) if isinstance(dim, int) else dim, reverse=True):
                shape[d_] = 1
            return out.reshape(shape)
    return out.squeeze()

def _triton_std(x, correction=1):
    N = x.numel()
    if N <= 1:
        return torch.tensor(0.0, device=x.device, dtype=x.dtype)
    mean = torch.empty(1, device=x.device, dtype=x.dtype)
    BLOCK_SIZE = 1024
    grid = (triton.cdiv(N, BLOCK_SIZE),)
    sum_kernel[grid](x, mean, N, BLOCK_SIZE=BLOCK_SIZE)
    mean_val = mean / N
    var_out = torch.zeros(1, device=x.device, dtype=x.dtype)
    std_kernel[grid](x, mean_val, var_out, N, correction, BLOCK_SIZE=BLOCK_SIZE)
    denom = N - correction
    denom = max(denom, 0)
    if denom <= 0:
        return torch.tensor(float('nan'), device=x.device, dtype=x.dtype)
    var = var_out / denom
    return torch.sqrt(var)

def sum_std(input, dim=None, keepdim=False, dtype=None, correction=1, out=None):
    sum_result = _triton_sum(input, dim=dim, keepdim=keepdim, dtype=dtype)
    std_result = _triton_std(sum_result, correction=correction)
    if keepdim:
        std_result = std_result.reshape([1] * sum_result.ndim)
    if out is not None:
        out.copy_(std_result)
        return out
    return std_result

