import torch
import triton
import triton.language as tl

@triton.jit
def mul_relu_kernel(in_ptr, other_ptr, out_ptr, n_elements, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements

    in_vals = tl.load(in_ptr + offsets, mask=mask, other=0.0)
    other_vals = tl.load(other_ptr + offsets, mask=mask, other=0.0)

    mul_vals = in_vals * other_vals
    relu_vals = tl.maximum(mul_vals, 0.0)

    tl.store(out_ptr + offsets, relu_vals, mask=mask)

def mul_relu(input: torch.Tensor, other, inplace: bool = False, out: torch.Tensor = None) -> torch.Tensor:
    if isinstance(other, (int, float)):
        other_tensor = torch.full_like(input, other)
    else:
        if not isinstance(other, torch.Tensor):
            other_tensor = torch.tensor(other, dtype=input.dtype, device=input.device)
        else:
            other_tensor = other

    if other_tensor.numel() == 1:
        other_tensor = other_tensor.expand_as(input)
    elif input.shape != other_tensor.shape:
        raise RuntimeError("input and other must be broadcastable to the same shape")

    if out is None:
        if inplace:
            out = input
        else:
            out = torch.empty_like(input)

    n_elements = input.numel()
    BLOCK_SIZE = 1024
    grid = (triton.cdiv(n_elements, BLOCK_SIZE),)

    mul_relu_kernel[grid](
        input, other_tensor, out, n_elements, BLOCK_SIZE=BLOCK_SIZE
    )

    return out

