import triton
import triton.language as tl
import torch

@triton.jit
def _fused_hstack_div_kernel(
    in_ptrs, divisor_ptr, out_ptr,
    total_elems: tl.constexpr,
    BLOCK_SIZE: tl.constexpr,
    IS_DIVISOR_SCALAR: tl.constexpr,
    ROUNDING_MODE: tl.constexpr,  # 0: none, 1: trunc, 2: floor
    IN_DTYPE: tl.constexpr,
    DIV_DTYPE: tl.constexpr,
    OUT_DTYPE: tl.constexpr,
    IS_INT_DIVISION: tl.constexpr,
):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < total_elems

    # Load input
    x = tl.load(in_ptrs + offsets, mask=mask, other=0.0)

    # Load divisor
    if IS_DIVISOR_SCALAR:
        d = tl.load(divisor_ptr)
    else:
        d = tl.load(divisor_ptr + offsets, mask=mask, other=1.0)

    # Compute division
    if IS_INT_DIVISION:
        x_float = x.to(tl.float32)
        d_float = d.to(tl.float32)
        result = x_float / d_float
    else:
        result = x / d

    # Apply rounding if needed
    if ROUNDING_MODE == 1:
        # Truncation towards zero
        result = result.to(tl.float32)
        result = tl.math.trunc(result)
    elif ROUNDING_MODE == 2:
        # Floor
        result = result.to(tl.float32)
        result = tl.math.floor(result)

    # Convert to output dtype
    if OUT_DTYPE == tl.float32:
        result = result.to(tl.float32)
    elif OUT_DTYPE == tl.float64:
        result = result.to(tl.float64)
    elif OUT_DTYPE == tl.int64:
        result = result.to(tl.int64)
    elif OUT_DTYPE == tl.int32:
        result = result.to(tl.int32)

    tl.store(out_ptr + offsets, result, mask=mask)


def _get_triton_dtype(torch_dtype):
    if torch_dtype == torch.float32:
        return tl.float32
    elif torch_dtype == torch.float64:
        return tl.float64
    elif torch_dtype == torch.int32:
        return tl.int32
    elif torch_dtype == torch.int64:
        return tl.int64
    elif torch_dtype == torch.float16:
        return tl.float16
    elif torch_dtype == torch.bfloat16:
        return tl.bfloat16
    else:
        raise ValueError(f"Unsupported dtype: {torch_dtype}")


def fused_hstack_div(tensors, divisor, *, rounding_mode=None, out=None):
    # Horizontal stacking
    stacked = torch.hstack(tensors)

    # Check if divisor is scalar
    if isinstance(divisor, (int, float)):
        divisor_tensor = torch.tensor(divisor, dtype=stacked.dtype, device=stacked.device)
        is_scalar = True
    else:
        divisor_tensor = divisor
        is_scalar = False

    # Determine output dtype based on PyTorch semantics
    # If both are integer types and rounding_mode is None, promote to float
    if rounding_mode is None:
        if torch.is_floating_point(stacked) or torch.is_floating_point(divisor_tensor):
            out_dtype = stacked.dtype if stacked.element_size() >= divisor_tensor.element_size() else divisor_tensor.dtype
        else:
            out_dtype = torch.get_default_dtype()
        is_int_division = True
    else:
        # Integer division with rounding mode keeps integer type?
        # PyTorch behavior: integer division with rounding mode returns integer
        if not torch.is_floating_point(stacked) and not torch.is_floating_point(divisor_tensor):
            out_dtype = stacked.dtype
            is_int_division = True
        else:
            out_dtype = torch.promote_types(stacked.dtype, divisor_tensor.dtype)
            is_int_division = False

    if out is not None:
        out_dtype = out.dtype

    # Flatten tensors for kernel processing
    stacked_flat = stacked.reshape(-1)
    if not is_scalar:
        divisor_flat = divisor_tensor.expand_as(stacked).reshape(-1)
    else:
        divisor_flat = divisor_tensor

    total_elems = stacked_flat.numel()

    in_dtype = _get_triton_dtype(stacked_flat.dtype)
    div_dtype = _get_triton_dtype(divisor_flat.dtype)
    out_triton_dtype = _get_triton_dtype(out_dtype)

    # Rounding mode encoding
    if rounding_mode is None:
        rm = 0
    elif rounding_mode == 'trunc':
        rm = 1
    elif rounding_mode == 'floor':
        rm = 2
    else:
        raise ValueError(f"Unknown rounding_mode: {rounding_mode}")

    # Allocate output if needed
    if out is None:
        result = torch.empty_like(stacked_flat, dtype=out_dtype)
    else:
        result = out.reshape(-1)

    BLOCK_SIZE = 1024
    grid = (triton.cdiv(total_elems, BLOCK_SIZE),)

    _fused_hstack_div_kernel[grid](
        stacked_flat, divisor_flat, result if out is None else out.reshape(-1),
        total_elems,
        BLOCK_SIZE,
        is_scalar,
        rm,
        in_dtype,
        div_dtype,
        out_triton_dtype,
        is_int_division,
    )

    if out is None:
        return result.reshape(stacked.shape)
    else:
        return out

